@page "/dispatcher"
@using ShipmentTracker.Client.Shared
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by tracking number or destination..."
           @bind="filterText" @bind:event="oninput" />
</div>

<button class="btn btn-success mb-3" @onclick="ToggleAddForm">@(showAddForm ? "Cancel" : "Add New Shipment")</button>

@if (showAddForm)
{
    <div class="card p-3 mb-3">
        <h4>New Shipment</h4>
        <div class="row g-2">
            <div class="col-md-4">
                <input class="form-control" placeholder="Tracking Number" @bind="newShipment.TrackingNumber" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
            </div>
            <div class="col-md-4">
                <label>Shipped Date</label>
                <input type="date" class="form-control" @bind="newShipment.ShippedDate" />
            </div>
            <div class="col-md-4">
                <label>Est. Delivery</label>
                <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
            </div>
        </div>
        <button class="btn btn-primary mt-2" @onclick="AddShipment">Create</button>
    </div>
}

@if (shipments == null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Update Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                    <td>@s.EstimatedDelivery.ToShortDateString()</td>
                    <td>
                        <select class="form-select form-select-sm" value="@((int)s.Status)"
                                @onchange="(e) => UpdateStatus(s, e)">
                            @foreach (ShipmentStatus status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showAddForm;
    private ShipmentDto newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments!.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
    }

    private void ToggleAddForm() => showAddForm = !showAddForm;

    private async Task AddShipment()
    {
        var response = await Http.PostAsJsonAsync("api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
            newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
            showAddForm = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
