@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private bool showAddForm;
    private ShipmentDto newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments!.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
    }

    private void ToggleAddForm() => showAddForm = !showAddForm;

    private async Task AddShipment()
    {
        var response = await Http.PostAsJsonAsync("api/shipments", newShipment);
        if (response.IsSuccessStatusCode)
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
            newShipment = new() { ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
            showAddForm = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        var newStatus = (ShipmentStatus)int.Parse(e.Value!.ToString()!);
        var response = await Http.PutAsJsonAsync($"api/shipments/{shipment.Id}/status", new { Status = newStatus });
        if (response.IsSuccessStatusCode)
        {
            shipment.Status = newStatus;
        }
    }

    private string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.InTransit => "info",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };
}

